import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"百鸟朝凤枪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/百鸟朝凤枪.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/百鸟朝凤枪.md"}'),s={name:"4.资源分区/6.技艺及称号/武技类/白刃类/百鸟朝凤枪.md"};function o(d,b,B,_,l,i){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"百鸟朝凤枪",tabindex:"-1"},[p("百鸟朝凤枪 "),r("a",{class:"header-anchor",href:"#百鸟朝凤枪","aria-label":'Permalink to "百鸟朝凤枪"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),n('<h1 id="百鸟朝凤枪-1" tabindex="-1">百鸟朝凤枪 <a class="header-anchor" href="#百鸟朝凤枪-1" aria-label="Permalink to &quot;百鸟朝凤枪&quot;">​</a></h1><p>百鸟朝凤枪<br> 描述：相传，武道宗师童渊观百禽搏空之态，悟天地灵动之势后，创下一门玄妙枪法，即所谓百鸟朝凤枪。<br> 此枪法有如灵鸟翻飞，攻守自若，无论是沙场厮杀，或者是阵前独斗，均有无穷妙用。童渊传于三个弟子，分别为“北地枪王”张绣，“西川枪王”张任，以及最为威名赫赫的“常胜将军”赵云。<br> 在兑换这门枪法时，轮回者需要绑定一个东方能量池，作为运用枪法的消耗。</p><p>枪意初鸣<br> 价格：D+500<br> 描述：你习得了百鸟朝凤枪之基础架势与运劲法门，枪势初具飞禽灵动之形，内劲运转间隐隐有鸟鸣相随。<br> 【百鸟枪势】：从现在开始，你可以每回合以一个自由动作，消耗2点能量，令你以“枪”专业进行的攻击具有【高速5】。这表现为你通过特殊的内劲运用法门，令你的每次出枪都更为快速凌厉。<br> 并且从现在开始，你可以在手持枪分类武器时，在一次攻击中进行【连射】。这一效果即使不消耗能量也可以生效。<br> 【沙场善战】：百鸟朝凤枪创于纷争之世，自然适应沙场征战，即使不眠不休的征战，也能屹立不倒。<br> 在兑换本等级技艺之后，只要你手中握持有枪，那么你就免受因为缺乏长休息带来的疲惫。</p><p>登党入室<br> 价格：C+1000<br> 描述：现在，你的枪法之中，能够显化飞禽真形，一招一式于灵动中暗藏杀机。<br> 【枪化百鸟】：现在，你获得了兑换百鸟朝凤枪下属枪式的权利。并且你每兑换一个枪式，你从【百鸟枪势】的效果中获得的【高速】的点数就提升5点。<br> 【沙场善战（提升）】：你更加不畏沙场征战的疲惫。从现在开始，你还能够免疫疲乏点数及其严重后果。</p><p>炉火纯青<br> 价格：B+2000<br> 描述：百禽真意融会贯通，枪意直冲云霄，枪锋所至，百鸟相随。<br> 【运用自如】：在对百鸟朝凤枪的枪意有了更为深刻的了解之后，你能够消耗更少的气力发出百鸟朝凤的枪招。<br> 你每回合额外获得4点AP用于转化施展百鸟朝凤枪所需的动作。<br> 【沙场善战（提升）】：无论在怎样激烈凶险的战场之上，你都不会选择恐惧与退缩，无双的枪意与你同在。<br> 你现在免疫恐惧点数及其严重后果。并且现在当你不再具有完好生命值时，你会具有【吸血3】，这并不表现为你进行了吸取血液，或者是汲取生命力等行为，而是表现为在逆境之中，你越战越勇，拥有从身体之中不断涌出的力量。</p><p>下属枪式：<br> 这些技艺都需要以分类为“枪”的武器进行施展。</p><p>燕掠式<br> 价格：C+1000<br> 描述：枪随身走如飞梭穿云，乃仿雨燕掠水之轻疾。<br> 消耗一个标准动作和6点能量，你可以施展燕掠式。燕掠式是一次可以结合入移动之中的白刃攻击。如果你将燕掠式的攻击结合到了一次移动之中，则这次移动的速度提升10米，并且你可以以燕掠式攻击移动路径上，触及范围内的所有敌方单位。<br> 由于燕掠式的出招轻快迅捷，你以燕掠式进行的攻击具有B级别的【先制】。<br> 招式推演：支付B+2000，你可以将燕掠式提升到B级。<br> 升级到B级之后，燕掠式的能量消耗将提升到10点。在C级的基础上，一回合一次，当施展燕掠式时，施展者可以直接额外获得一个移动动作，用来进行与燕掠式的攻击进行的结合的移动。并且这次移动的速度在C级的基础上，再额外提升60米，同时你在C级燕掠式中获得的【先制】将会改为A级别的【措手不及】，由于出招更为快绝，你还会在攻击上得到一级的加骰的提升（最高为8加骰）。</p><p>鹰击式<br> 价格：C+1000<br> 描述：枪出发劲如陨星坠空，乃仿苍鹰扑杀之刚猛<br> 消耗一个标准动作和6点能量，你可以施展鹰击式。鹰击式是一次白刃攻击，且必须是一次全力攻击。以鹰击式进行的这次白刃攻击能够无视对手的护甲和天生防御，这是一个【接触攻击】效果。<br> 由于鹰击式的枪势刚强而毫无保留，你在以鹰击式进行的这次白刃攻击中，额外具有力量上的附加成功*2点的技艺减值，以及与技艺减值等量的附加成功。<br> 招式推演：支付B+2000，你可以将鹰击式提升到B级。<br> 升级到B级之后，鹰击式的能量消耗将提升到10点。要施展B级的鹰击式，你需要在本轮内已经施展过其他任意一个B级别的下属枪式。以强绝枪劲施展的鹰击式更加威力惊人，不再需要以枪劲隔山打牛，而是能够洞穿一切阻拦之物，所以，以B级鹰击式进行的这次攻击将不再具有【接触攻击】，而是改为获得B级别创伤来源的忽略天生防御和忽略盔甲防御效果。<br> 除此之外，现在你在以鹰击式进行的这次白刃攻击中，所具有的技艺减值降低到力量上的附加成功*1点，同时，获得的“与技艺减值等量的附加成功”改为“力量上的附加成功*4点。”</p><p>鹤舞式<br> 价格：C+1000<br> 描述：枪圈画圆如白羽蔽天，乃仿仙鹤御敌之从容<br> 消耗一个标准动作和6点能量，你可以施展鹤舞式。鹤舞式是一次白刃攻击。在以鹤舞式进行攻击的同时，你可以不消耗动作的进行一次以分类为“枪”的武器进行的白刃格挡。<br> 由于鹤舞式的防守密不透风，你在以鹰击式进行的这次白刃格挡中，你手持的枪类武器额外具有【格挡X】，X的数值等同你的武技等级，至多为14。同时在这次白刃格挡维持的时间内，你在反射豁免上具有4点技艺加值。<br> 招式推演：支付B+2000，你可以将鹤舞式提升到B级。<br> 升级到B级之后，鹤舞式的能量消耗将提升到10点。在C级的基础上，一回合一次，当你维持着以鹤舞式进行的白刃格挡时，你可以将自己受到的一次近战伤害减半。<br> 同时在维持鹤舞式的白刃格挡期间，你还会获得传奇敏捷*2点的远程伤害吸收和【防弹】特性。这表现你快速舞枪，足以将射向你的暗器流矢统统打落。</p><p>雀啄式<br> 价格：C+1000<br> 描述：枪尖颤振如暴雨打萍，乃仿灵雀啄食之迅疾<br> 消耗一个标准动作和6点能量，你可以施展雀啄式。雀啄式是一次白刃攻击。在以鹤舞式进行攻击的时，你可以投掷两次攻击检定，取更好的一次结果。<br> 由于雀啄式的攻势绵密不断，令对手难以逃避，对手应对这次攻击需要以反射豁免应对，而非经过防御。在进行这次攻击时，你通过主轴D级的【百鸟枪势】效果获得的【高速】提升10点。<br> 招式推演：支付B+2000，你可以将雀啄式提升到B级。<br> 升级到B级之后，雀啄式的能量消耗将提升到10点。由于你的发劲更加精妙绝伦，一息之间所能够发出的刺击更为繁多，在C级的基础上，你施展雀啄式时可以进行两次白刃攻击而不是一次，这两次攻击都享有雀啄击式带来的增益。<br> 施展B级的雀啄式时，只要两次攻击中的第一次攻击命中，那么对方就需要进行反射豁免，DC为攻击的成功数，若对方失败则在应对雀啄式的第二次攻击时获得反射豁免上的【劣化2】，并且在进行反射豁免时承受12点的技艺减值，这是一个B级别幻象来源的负面效果。</p><p>鹏扬式<br> 价格：C+1000<br> 描述：枪杆卷云涛撼地，借大鹏扶摇之势镇压八荒<br> 消耗一个标准动作和6点能量，你可以施展鹏扬式。要施展鹏扬起式，你必须在本轮内已经施展过一次其他的下属枪式。在画风上，你会借助前一招的劲力，以枪身弹性令自己飞腾到空中，宛如大鹏扶摇而上，随后借助落下之势，将长枪劈下。<br> 鹏扬式是一次白刃攻击，会对前方30米扇形范围内的所有角色造成伤害。<br> 由于雀啄式的枪劲强横，能够掀起气浪，冲溃敌军，你的这次攻击附带【碾压】特性，并且具有所绑定的能量池等级*3点的能量加值。<br> 招式推演：支付B+2000，你可以将鹏扬式提升到B级。<br> 升级到B级之后，鹏扬式的能量消耗将提升到10点。要施展B级的鹏扬式，需要你在上一轮内已经施展过其他任意一个B级别的下属枪式。<br> 在你对于鹏扬式的理解更为精要之后，你高空落下一击而激荡而出的气浪便更会有无穷的威力！<br> 在施展B级的鹏扬式时，在C级的基础上，这个技艺的范围扩大到70米圆形范围内的所有角色。并且这次攻击所具有的能量加值提升到绑定能量池等级*6点，且造成的伤害翻倍。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const C=e(s,[["render",o]]);export{h as __pageData,C as default};
